mapper.select:
SELECT A.DPRT_CD AS CODE
      ,A.DPRT_NM AS NAME
  FROM NIC41B A
 WHERE A.USE_CCD = 'Y'

   AND (
         (
           ( A.DPRT_CD >= #{DPRT_CD0} AND A.DPRT_CD < = #{DPRT_CD1} )
           AND A.DPRT_CD NOT IN

               #{BRANCH_EX_NOT_LIST}

          )
          OR A.DPRT_CD IN

          #{BRANCH_EX_LIST}

       )
 ORDER BY A.DPRT_CD


   AND A.DPRT_CD IN ( SELECT B.DPRT_CD
                        FROM NIC41B B
                       START WITH B.DPRT_CD = #{DPRT_CD}
                     CONNECT BY PRIOR B.DPRT_CD = DECODE(B.DPRT_CD, #{DPRT_CD}, '-1', B.HG_RNK_DPRT_CD)
                    )

SELECT A.ACCESS_YN
  FROM C_GROUP_ROLE_MENU_ACT_AUTH A
 WHERE A.MENU_ACT_ID = #{MENU_ACT_ID}

SELECT /* AML_00_offduty_getOffDutyCheck */ CASE WHEN S.CUR_YMD > #{OFF_DUTY_START_DT} THEN 'ERROR' ELSE 'PASS' END AS OFF_DUTY_CHECK_DT ,CASE WHEN 'A' = #{CHECK_FLAG} THEN CASE WHEN U.OFF_DUTY_A_OFF > 0 THEN 'ERROR_A_OFF' WHEN U.OFF_DUTY_A_AGENT > 0 THEN 'ERROR_A_AGT' ELSE 'PASS' END WHEN 'O' = #{CHECK_FLAG} THEN CASE WHEN U.OFF_DUTY_O_OFF > 0 THEN 'ERROR_O_OFF' WHEN U.OFF_DUTY_O_AGENT > 0 THEN 'ERROR_O_AGT' ELSE 'PASS' END WHEN 'AO' = #{CHECK_FLAG} THEN CASE WHEN U.OFF_DUTY_A_OFF > 0 THEN 'ERROR_A_OFF' WHEN U.OFF_DUTY_A_AGENT > 0 THEN 'ERROR_A_AGT' WHEN U.OFF_DUTY_O_OFF > 0 THEN 'ERROR_O_OFF' WHEN U.OFF_DUTY_O_AGENT > 0 THEN 'ERROR_O_AGT' ELSE 'PASS' END ELSE 'ERROR_FLAG' END AS OFF_DUTY_CHECK_CNT ,CASE WHEN D.DEP_CNT > 0 THEN 'ERROR' ELSE 'PASS' END AS OFF_DUTY_CHECK_DEP FROM ( SELECT /* A: AGENT(대리인) * 대직요청이 없어야 한다. * O: OFF(요청인) * 대직 중이거나 기 대직요청이 없어야 한다. */ COUNT( CASE WHEN 'A' = #{CHECK_FLAG} OR 'AO' = #{CHECK_FLAG} THEN CASE WHEN C.OFF_USER_ID = #{AGENT_USER_ID} THEN C.OFF_USER_ID END END) AS OFF_DUTY_A_OFF ,COUNT( CASE WHEN 'A' = #{CHECK_FLAG} OR 'AO' = #{CHECK_FLAG} THEN CASE WHEN C.AGENT_USER_ID = #{AGENT_USER_ID} AND C.OFF_USER_ID = #{OFF_USER_ID} THEN C.OFF_USER_ID END END) AS OFF_DUTY_A_AGENT ,COUNT( CASE WHEN 'O' = #{CHECK_FLAG} OR 'AO' = #{CHECK_FLAG} THEN CASE WHEN C.OFF_USER_ID = #{OFF_USER_ID } THEN C.OFF_USER_ID END END) AS OFF_DUTY_O_OFF ,COUNT( CASE WHEN 'O' = #{CHECK_FLAG } OR 'AO' = #{CHECK_FLAG } THEN CASE WHEN C.AGENT_USER_ID = #{OFF_USER_ID } THEN C.AGENT_USER_ID END END) AS OFF_DUTY_O_AGENT FROM C_OFF_DUTY_USER C WHERE 1 = 1 AND C.DEL_YN = 'N' AND ( C.AGENT_USER_ID = #{AGENT_USER_ID } OR C.AGENT_USER_ID = #{OFF_USER_ID } OR C.OFF_USER_ID = #{AGENT_USER_ID } OR C.OFF_USER_ID = #{OFF_USER_ID } )
AND C.OFF_DUTY_ID != #{OFF_DUTY_ID }
AND C.OFF_DUTY_START_DT <= #{OFF_DUTY_EXPECT_DT } || '235959' AND C.OFF_DUTY_EXPECT_DT >= #{OFF_DUTY_START_DT } || '000000' ) U ,(SELECT TO_CHAR(SYSDATE, 'YYYYMMDD') AS CUR_YMD FROM DUAL WHERE 1 = 1) S ,(SELECT COUNT(M.DEP_ID) AS DEP_CNT FROM (SELECT A.DEP_ID FROM C_USER A WHERE 1 = 1 AND A.USER_ID = #{AGENT_USER_ID } MINUS SELECT B.DEP_ID FROM C_USER B WHERE 1 = 1 AND B.USER_ID = #{OFF_USER_ID } ) M ) D WHERE 1 = 1

