mapper.select:
SELECT NVL(SUBSTR(C.LAST_USE_DATE, 1, 8), TO_CHAR(SYSDATE,'YYYYMMDD') ) AS LAST_USE_DATE
  FROM C_USER C
 WHERE C.LOGIN_ID = #{LOGIN_ID}

   SELECT A.RT3K_7 AS CD_NM, A.RT3K_A AS CD_ID
     FROM BRT3K0TB A
    WHERE A.RT31_1 = #{RT31_1}
      AND A.RT32_1 = #{RT32_1}
      AND A.RT3K_A IS NOT NULL
UNION ALL
   SELECT B.RT33_3, B.RT33_5
     FROM BRT330TB B
    WHERE B.RT31_1 = #{RT31_1}
      AND B.RT32_1 = #{RT32_1}
      AND B.RT33_5 IS NOT NULL

SELECT *
  FROM C_WINDOW_DISPLAY A
 WHERE A.LANG_CD = #{LANG_CD}
   AND A.WINDOW_ACT_ID = #{WINDOW_ACT_ID}

SELECT A.MENU_ACT_ID
  FROM C_GROUP_ROLE_MENU_ACT_AUTH A
 INNER JOIN C_MENU_WINDOW_MAP B
    ON A.MENU_ACT_ID = B.MENU_ACT_ID
 WHERE A.ACCESS_YN = 'Y'
   AND A.GROUP_ID = #{GROUP_ID}
   AND A.ROLE_ID = #{ROLE_ID}
   AND B.WINDOW_ACT_ID = #{WINDOW_ACT_ID}

SELECT C.ROLE_ID, C.ROLE_NM
  FROM C_ROLE C
 WHERE C.ROLE_ID = #{ROLE_ID}
